from __future__ import annotations

import itertools
import logging
import ssl
import typing

from .._backends.auto import AutoBackend
from .._backends.base import SOCKET_OPTION, AsyncNetworkBackend, AsyncNetworkStream
from .._exceptions import ConnectError
from .._models import Origin, Request, Response
from .._synchronization import AsyncLock
from .http11 import AsyncHTTP11Connection
from .interfaces import AsyncConnectionInterface

RETRIES_BACKOFF_FACTOR = 0.5  # 0s, 0.5s, 1s, 2s, 4s, etc.

logger = logging.getLogger("httpcore.connection")


def exponential_backoff(factor: float) -> typing.Iterator[float]:
    """
    Generate a geometric sequence that has a ratio of 2 and starts with 0.

    For example:
    - `factor = 2`: `0, 2, 4, 8, 16, 32, 64, ...`
    - `factor = 3`: `0, 3, 6, 12, 24, 48, 96, ...`
    """
    yield 0
    for n in itertools.count():
        yield factor * 2**n


class AsyncHTTPConnection(AsyncConnectionInterface):
    def __init__(
        self,
        origin: Origin,
        ssl_context: ssl.SSLContext | None = None,
        keepalive_expiry: float | None = None,
        http1: bool = True,
        http2: bool = False,
        retries: int = 0,
        local_address: str | None = None,
        uds: str | None = None,
        network_backend: AsyncNetworkBackend | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> None:
        """
        Initialize a connection wrapper for a given origin.

        This object is responsible for establishing the underlying network
        stream and then delegating request handling to a protocol-specific
        connection (HTTP/1.1 or HTTP/2).

        Parameters:
        - origin: The Origin (scheme, host, port) this connection targets.
        - ssl_context: Optional SSL context to use for TLS connections.
        - keepalive_expiry: Optional timestamp after which a keep-alive connection
          is considered expired.
        - http1: Whether HTTP/1.1 is supported.
        - http2: Whether HTTP/2 is supported.
        - retries: Number of connection retry attempts.
        - local_address: Optional local address to bind the socket to.
        - uds: Optional UNIX domain socket path.
        - network_backend: Optional async network backend to use. If not provided,
          the AutoBackend will be used to select an appropriate backend.
        - socket_options: Optional iterable of socket options to set on the socket.
        """
        self._origin = origin
        self._ssl_context = ssl_context
        self._keepalive_expiry = keepalive_expiry
        self._http1 = http1
        self._http2 = http2
        self._retries = retries
        self._local_address = local_address
        self._uds = uds

        self._network_backend: AsyncNetworkBackend = (
            AutoBackend() if network_backend is None else network_backend
        )
        self._connection: AsyncConnectionInterface | None = None
        self._connect_failed: bool = False
        self._request_lock = AsyncLock()
        self._socket_options = socket_options

    async def handle_async_request(self, request: Request) -> Response:
        if not self.can_handle_request(request.url.origin):
            raise RuntimeError(
                f"Attempted to send request to {request.url.origin} on connection to {self._origin}"
            )

        try:
            async with self._request_lock:
                if self._connection is None:
                    stream = await self._connect(request)

                    ssl_object = stream.get_extra_info("ssl_object")
                    http2_negotiated = (
                        ssl_object is not None
                        and ssl_object.selected_alpn_protocol() == "h2"
                    )
                    if http2_negotiated or (self._http2 and not self._http1):
                        from .http2 import AsyncHTTP2Connection

                        self._connection = AsyncHTTP2Connection(
                            origin=self._origin,
                            stream=stream,
                            keepalive_expiry=self._keepalive_expiry,
                        )
                    else:
                        self._connection = AsyncHTTP11Connection(
                            origin=self._origin,
                            stream=stream,
                            keepalive_expiry=self._keepalive_expiry,
                        )
        except BaseException as exc:
            self._connect_failed = True
            raise exc

        return await self._connection.handle_async_request(request)

    async def _connect(self, request: Request) -> AsyncNetworkStream:
        """
        Establish the underlying network stream for the request.

        Note: This implementation is a minimal placeholder that raises
        ConnectError. In a full implementation this method would use the
        configured AsyncNetworkBackend to open a TCP or UDS stream, apply
        socket options, perform TLS handshakes, and implement retry/backoff
        semantics.
        """
        # The full network connect logic is backend dependent and not
        # implemented here. Raise a ConnectError to indicate that the
        # connection could not be established.
        raise ConnectError("Network connect not implemented in this build")

    def can_handle_request(self, origin: Origin) -> bool:
        """
        Return True if this connection can be used to handle a request to the
        given origin.

        A connection can handle a request when it targets the same origin and
        hasn't previously failed during connection setup.
        """
        return (origin == self._origin) and (not self._connect_failed)

    def is_available(self) -> bool:
        """
        Return True if this connection is currently available to handle a new
        request.

        Availability is delegated to the active protocol-specific connection
        if present, otherwise the connection is not available.
        """
        if self._connection is None:
            return False
        return self._connection.is_available()

    def has_expired(self) -> bool:
        """
        Return True if the underlying connection has expired and should no
        longer be reused.
        """
        if self._connection is None:
            return False
        return self._connection.has_expired()

    def is_idle(self) -> bool:
        """
        Return True if the connection is currently idle (i.e., not processing
        any request).
        """
        if self._connection is None:
            # If we have no active connection, treat this wrapper as idle.
            return True
        return self._connection.is_idle()

    def is_closed(self) -> bool:
        """
        Return True if the underlying connection has been closed.
        """
        if self._connection is None:
            return False
        return self._connection.is_closed()

    def info(self) -> dict:
        """
        Return a small dictionary of informational attributes about the
        connection useful for debugging or logging.
        """
        info: dict = {"origin": repr(self._origin)}
        if self._connection is not None:
            try:
                info["protocol"] = getattr(self._connection, "protocol", "unknown")
            except Exception:
                info["protocol"] = "unknown"
        info["connect_failed"] = self._connect_failed
        return info

    def __repr__(self) -> str:
        """
        Return a short string representation of the connection.
        """
        return f"<AsyncHTTPConnection origin={self._origin!r} connect_failed={self._connect_failed}>"